import React, { useState, useEffect } from 'react';
import { useTrail, useTransition, animated } from 'react-spring';
import Card from '../Card';
import styled from 'styled-components';

const Wrapper = styled.div`
  display: flex;
  margin: auto;
  width: 100%;
  max-width: ${props => props.theme.screens.sm};
  justify-content: center;
  flex-flow: row wrap;
  > div {
    display: inline-flex;
    max-width: 270px;
    max-height: calc( 95vh / 2 );
  }
  }
`
const CardGrid = ({ items }) => {
  const [anyIsHovered, setanyIsHovered] = useState(false);
  const config = { mass: 5, tension: 2000, friction: 200 };


  return (
    <Wrapper>
      {items.map(( item ) => {
        return <Card key={`${item.id}-d`} anyIsHovered={anyIsHovered} onMouseOver={() => setanyIsHovered(true)} onMouseLeave={() => setanyIsHovered(false)} item={item} title={item.name} />;
      })}
    </Wrapper>
  );
};

export default CardGrid;
