import React, { useRef, useEffect, useState } from 'react';
import PropTypes from 'prop-types';
import { Link } from 'gatsby';
import styled from 'styled-components';
import tw from 'tailwind.macro';
import { useSpring, animated } from 'react-spring';

const AniCard = animated(styled.div`
  ${tw`relative center bg-card`};
  width: 100%;
  height: 100%;
  background-color: gray;
  transition: box-shadow 0.3s ease-in-out;

  &::after {
    content: " ";
    height: 100%;
    width: 100%;
    position: absolute;
    transition: opacity 0.33s ease-in-out;
    box-shadow: 0px 0px 15px 5px rgba(0, 0, 0, 0.5);
    opacity: ${props => props.isHovered ? 1 : 0};
  }
  `);
const Wrap = animated(styled.div`
  position: relative;
  min-height: 200px;
  min-width: 150px;
  width: 50%;
  max-width: calc(50vw - 3vw);
  padding-top: 0.5em;
  padding-bottom: 0.5em;
  padding-left: 0.5em;
  padding-right: 0.5em;
`);


const CardContent = styled.div`
  ${tw`px-2 m-auto`}
`;
const CardTitle = styled.h3`
  ${tw`text-white w-full px-2 absolute pin-b `}
  font-family: ${props => props.theme.type.heading};
`;

const Card = ({ item, onClick, onMouseOver, onMouseLeave, anyIsHovered, children, ...rest }) => {
  const [isHovered, setHover] = useState(false);

  const hoverProps = useSpring({
    transform: `${isHovered ? `scale3d(1.10,1.10,1.10)` : anyIsHovered ? `scale3d(0.9,0.9,0.9)`:  `scale3d(0.98,0.98,0.98)`} translateZ(100px)`,
    opacity: `${!isHovered && anyIsHovered ? '0.75' : '1' }`,
  });

  const springProps = useSpring({
    to: {  transform: 'scale3d(1, 1, 1)',  opacity: 1 },
    from: {  transform: 'scale3d(0.80, 0.80, 0.80)', opacity: 0 },
  });


  return (
    <Wrap
      style={hoverProps}
      onMouseOver={() => {
        onMouseOver && onMouseOver();
        setHover(true)

      }}
      onMouseLeave={() => {
        onMouseOver && onMouseLeave();
        setHover(false)
      }}
    >
      <AniCard key={`${item.id}-card `} style={springProps} isHovered={isHovered}>
        {children && <CardContent>{children}</CardContent>}
        <CardTitle>{item.name || item.title}</CardTitle>
      </AniCard>
    </Wrap>
  );
};

export default Card;

Card.PropTypes = {
  item: PropTypes.object.isRequired,

}